import requests

base_url = "http://localhost:15672"
username = "guest"
password = "guest"

def create_vhost(vhost):
    url = f"{base_url}/api/virtual-hosts/{vhost}"
    headers = {"Content-Type": "application/json", "Authorization": f"Basic {requests.utils.quote_basic_auth(username, password)}"}
    response = requests.post(url, headers=headers)
    return response.json()['name']

def create_user(vhost, username):
    vhost_path = create_vhost(vhost)
    url = f"{base_url}/api/users/{username}"
    headers = {"Content-Type": "application/json"}
    response = requests.post(url, json={"password": "new_password"}, headers=headers)
    return username

def grant_permissions(vhost, user, permissions):
    vhost_path = create_vhost(vhost)
    user_path = create_user(vhost, user)
    url = f"{base_url}/api/users/{user_path}/permissions/{vhost_path}"
    headers = {"Content-Type": "application/json", "Authorization": f"Basic {requests.utils.quote_basic_auth(username, password)}"}
    response = requests.put(url, json={"configure": ".*", "write": ".*", "read": ".*"}, headers=headers)
    return user

# Create two virtual hosts
vhost1 = create_vhost("app1")
vhost2 = create_vhost("app2")

# Create users for each vhost and grant permissions
grant_permissions(vhost1, "user1", ["configure", "write", "read"])
grant_permissions(vhost2, "user2", ["configure", "write", "read"])